        # For vertical: minus=left, plus=right
        # For horizontal: minus=top, plus=bottom
        if double_side == 'minus':
            ray_side = 'plus'
        else:
            ray_side = 'minus'

        # Cap is at the end where the double is
        # Index 0 = cap end
        cap_at_start = (double_end == 'start')

