                    if on_path:
                        if bar['cap_at_start']:
                            index = mr - bar['rmin']
                        else:
                            index = bar['rmax'] - mr
            else:  # horizontal
                if bar['cmin'] <= mc <= bar['cmax']:
                    if bar['ray_side'] == 'minus':
                        # Rays go UP from rmin-1 to 0
                        if mr < bar['rmin']:
                            on_path = True
                    else:
                        # Rays go DOWN from rmax+1 to H-1
                        if mr > bar['rmax']:
                            on_path = True
                    if on_path:
                        if bar['cap_at_start']:
                            index = mc - bar['cmin']
                        else:
                            index = bar['cmax'] - mc

            if on_path and index is not None:
                index_color_map[index] = marker_color
                break

