                    for c in range(0, bar['cmin']):
                        output[row][c] = color
                else:
                    # Fill right from cmax+1 to W-1
                    for c in range(bar['cmax']+1, W):
                        output[row][c] = color
            else:  # horizontal
                if bar['cap_at_start']:
                    col = bar['cmin'] + idx
                else:
                    col = bar['cmax'] - idx

                if bar['ray_side'] == 'minus':
                    # Fill up from rmin-1 to 0
                    for r in range(0, bar['rmin']):
                        output[r][col] = color
                else:
                    # Fill down from rmax+1 to H-1
                    for r in range(bar['rmax']+1, H):
                        output[r][col] = color

