        for c in range(W):
            if grid[r][c] != 8 and not visited[r][c]:
                q = deque([(r, c)])
                visited[r][c] = True
                cells = []
                while q:
                    cr, cc = q.popleft()
                    cells.append((cr, cc))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < H and 0 <= nc < W and not visited[nr][nc] and grid[nr][nc] != 8:
                            visited[nr][nc] = True
                            q.append((nr, nc))
                if len(cells) == 1:
                    markers.append(cells[0])
                else:
                    bars.append(cells)

    # Analyze each bar
    bar_infos = []
    for cells in bars:
        rows = [r for r, c in cells]
        cols = [c for r, c in cells]
        rmin, rmax = min(rows), max(rows)
        cmin, cmax = min(cols), max(cols)
        h = rmax - rmin + 1
        w = cmax - cmin + 1

        if w == 2:  # vertical
            track_minus = [grid[r][cmin] for r in range(rmin, rmax+1)]
            track_plus = [grid[r][cmax] for r in range(rmin, rmax+1)]
            orientation = 'vertical'
        else:  # horizontal
            track_minus = [grid[rmin][c] for c in range(cmin, cmax+1)]
            track_plus = [grid[rmax][c] for c in range(cmin, cmax+1)]
            orientation = 'horizontal'

        length = h if orientation == 'vertical' else w

        # Find double pattern to determine cap position and ray direction
        double_side = None
        double_end = None

        for track, side in [(track_minus, 'minus'), (track_plus, 'plus')]:
            if track[0] == track[1] and track[0] != track[2]:
                double_side = side
                double_end = 'start'
                break
            if track[-1] == track[-2] and track[-1] != track[-3]:
                double_side = side
                double_end = 'end'
                break

        # Ray direction: opposite to the side with the double
        if double_side == 'minus':
            ray_side = 'plus'
        else:
            ray_side = 'minus'

        # Cap is at the end where the double is
        cap_at_start = (double_end == 'start')

        bar_infos.append({
            'orientation': orientation,
            'length': length,
            'rmin': rmin, 'rmax': rmax,
            'cmin': cmin, 'cmax': cmax,
            'ray_side': ray_side,
            'cap_at_start': cap_at_start,
        })

    # For each marker, find which bar's ray path it lies on
    index_color_map = {}

    for mr, mc in markers:
        marker_color = grid[mr][mc]

        for bi, bar in enumerate(bar_infos):
            on_path = False
            index = None

            if bar['orientation'] == 'vertical':
                if bar['rmin'] <= mr <= bar['rmax']:
                    if bar['ray_side'] == 'minus':
                        if mc < bar['cmin']:
                            on_path = True
                    else:
                        if mc > bar['cmax']:
                            on_path = True
                    if on_path:
                        if bar['cap_at_start']:
                            index = mr - bar['rmin']
                        else:
                            index = bar['rmax'] - mr
            else:  # horizontal
                if bar['cmin'] <= mc <= bar['cmax']:
                    if bar['ray_side'] == 'minus':
                        if mr < bar['rmin']:
                            on_path = True
                    else:
                        if mr > bar['rmax']:
                            on_path = True
                    if on_path:
                        if bar['cap_at_start']:
                            index = mc - bar['cmin']
                        else:
                            index = bar['cmax'] - mc

            if on_path and index is not None:
                index_color_map[index] = marker_color
                break

    # Apply rays to all bars
    for bar in bar_infos:
        for idx, color in index_color_map.items():
            if bar['orientation'] == 'vertical':
                if bar['cap_at_start']:
                    row = bar['rmin'] + idx
                else:
                    row = bar['rmax'] - idx

                if bar['ray_side'] == 'minus':
                    for c in range(0, bar['cmin']):
                        output[row][c] = color
                else:
                    for c in range(bar['cmax']+1, W):
                        output[row][c] = color
            else:  # horizontal
                if bar['cap_at_start']:
                    col = bar['cmin'] + idx
                else:
                    col = bar['cmax'] - idx

                if bar['ray_side'] == 'minus':
                    for r in range(0, bar['rmin']):
                        output[r][col] = color
                else:
                    for r in range(bar['rmax']+1, H):
                        output[r][col] = color

    return output

```

